sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading)
        return;

    // Loan Amount Currency Field

    var loanAmount = g_form.getValue('loan_amount');

    if (loanAmount.indexOf(';') > -1)
        loanAmount = loanAmount.split(';')[1];

    loanAmount = parseFloat(
        loanAmount.replace(/,/g, '')
    ) || 0;

    // EMI Currency Field

    var emiAmount = g_form.getValue('emi_amount');

    if (emiAmount.indexOf(';') > -1)
        emiAmount = emiAmount.split(';')[1];

    emiAmount = parseFloat(
        emiAmount.replace(/,/g, '')
    ) || 0;

    // Total Paid Months

    var paidMonths = parseInt(
        g_form.getValue('total_paid_months'),
        10
    ) || 0;

    // Outstanding Amount

    var outstanding =
        loanAmount - (emiAmount * paidMonths);

    if (outstanding < 0)
        outstanding = 0;

    g_form.setValue(
        'outstanding_amount',
        'USD;' + outstanding.toFixed(2)


    );
	alert(
    'Loan=' + loanAmount +
    '\nEMI=' + emiAmount +
    '\nMonths=' + paidMonths +
    '\nOutstanding=' + outstanding
);

}
